418→  timeout: number;
419→  env?: NodeJS.ProcessEnv;
420→  signal?: AbortSignal;
421→}
422→
423→/** @internal Exported for testing only */
424→export function spawnAsync(
425→  command: string,
426→  args: string[],
427→  options: SpawnOptions,
428→): Promise<SpawnResult> {
429→  return new Promise((resolve, reject) => {
430→    let stdout = "";
431→    let stderr = "";
432→    let settled = false;
433→
434→    const proc = spawn(command, args, {
435→      stdio: ["pipe", "pipe", "pipe"],
436→      env: options.env,
437→      detached: true,
438→    });
439→
440→    const settle = (
441→      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
442→    ) => {
443→      if (settled) return;
444→      settled = true;
445→      clearTimeout(timeoutId);
446→      options.signal?.removeEventListener("abort", onAbort);
447→      if (outcome.ok) {
448→        resolve(outcome.result);
449→      } else {
450→        reject(outcome.error);
451→      }
452→    };
453→
454→    const timeoutId = setTimeout(() => {
455→      killProcessGroup(proc);
456→      settle({
457→        ok: false,
458→        error: new Error(`Process timed out after ${options.timeout}ms`),
459→      });
460→    }, options.timeout);
461→
462→    const onAbort = () => {
463→      killProcessGroup(proc);
464→      settle({ ok: false, error: new Error("Cancelled by client") });
465→    };
466→
467→    if (options.signal) {
468→      if (options.signal.aborted) {
469→        killProcessGroup(proc);
470→        clearTimeout(timeoutId);
471→        reject(new Error("Cancelled by client"));
472→        return;
473→      }
474→      options.signal.addEventListener("abort", onAbort, { once: true });
475→    }
476→
477→    proc.stdout.on("data", (data: Buffer) => {
478→      stdout += data.toString();
479→    });
480→
481→    proc.stderr.on("data", (data: Buffer) => {
482→      stderr += data.toString();
483→    });
484→
485→    proc.on("error", (err: NodeJS.ErrnoException) => {
486→      if (err.code === "ENOENT") {
487→        settle({
488→          ok: false,
489→          error: new Error(
490→            `Command not found: ${command}. Ensure it is installed and in PATH.`,
491→          ),
492→        });
493→      } else {
494→        settle({
495→          ok: false,
496→          error: new Error(`Failed to spawn process: ${err.message}`),
497→        });
498→      }
499→    });
500→
501→    proc.on("close", (code: number | null) => {
502→      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
503→    });
504→  });
505→}
506→
507→const SIGKILL_GRACE_MS = 5000;
508→
509→function killProcessGroup(proc: ReturnType<typeof spawn>): void {
510→  let exited = false;
511→  proc.on("close", () => {
512→    exited = true;
513→  });
514→
515→  sendSignal(proc, "SIGTERM");
516→
517→  setTimeout(() => {
518→    if (!exited) {
519→      sendSignal(proc, "SIGKILL");
520→    }
521→  }, SIGKILL_GRACE_MS).unref();
522→}
523→
524→function sendSignal(
525→  proc: ReturnType<typeof spawn>,
526→  signal: NodeJS.Signals,
527→): void {
528→  try {
529→    if (proc.pid) {
530→      process.kill(-proc.pid, signal);
531→    }
532→  } catch {
533→    // Process group may already be gone — fall back to direct kill
534→    if (!proc.killed) {
535→      proc.kill(signal);
536→    }
537→  }
538→}
